import "../App/App.scss";
import Header from "../Header/Header";
import "bootstrap/dist/css/bootstrap.min.css";
import { Button } from "react-bootstrap";

const App = () => {
  return (
    <div className="app">
      <Header />
      <div className="container app__hero">
        <div className="row">
          <div className="col-lg-6">
            <div className="app__hero__name">
              <p className="">
                Hi, my name is{" "}
                <b>
                  <span className="text-green text-bold ">Emeka Osuji</span>
                </b>
              </p>
              {/* <div className="horizontal-line"></div> */}
              <h1 className="text-bold text-arimo">
                Front End Developer
                <br /> & UI Designer
              </h1>
              <p className="app__hero__desc pt-3">
                I am a developer and designer of web and mobile apps. Currently,
                I spend most of my time honing my development & design skills
                and also becoming a better human.
              </p>
              <Button className="btn-green my-3">Get In Touch</Button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default App;
